INSERT INTO `slr_rule_json`
VALUES (19, 'R1873910811026657280',
        '{\"alertIntervalUnit\":\"分钟\",\"alertIntervalValue\":5,\"alertMessage\":\"[异常高频抽奖]${KafkaEventDTO.eventAttrMap.bankName}: ${KafkaEventDTO.eventAttrMap.campaignName}(${KafkaEventDTO.eventAttrMap.campaignId})中游戏用户(${KafkaEventDTO.targetValue})最近${RuleInfoDTO.ruleCondGroup.0.windowValue}${RuleInfoDTO.ruleCondGroup.0.windowUnit}内抽奖数量为${ProcessorDTO.eventFieldAndValueSumMap.lottery}，超过${RuleInfoDTO.ruleCondGroup.0.threshold}次，请您及时查看原因！\",\"channel\":\"GAME\",\"modelCode\":\"M1873324910378618880\",\"modelGroovy\":\"package com.liboshuai.slr.module.engine.processor.impl\\n\\n\\nimport com.liboshuai.slr.framework.common.constants.RedisKeyConstants\\nimport com.liboshuai.slr.framework.common.enums.CommonStatusEnum\\nimport com.liboshuai.slr.module.engine.dto.*\\nimport com.liboshuai.slr.module.engine.enums.RuleCondCombOpEnum\\nimport com.liboshuai.slr.module.engine.enums.RuleCondTypeEnum\\nimport com.liboshuai.slr.module.engine.enums.TimeUnitEnum\\nimport com.liboshuai.slr.module.engine.framework.exception.BusinessException\\nimport com.liboshuai.slr.module.engine.processor.Processor\\nimport com.liboshuai.slr.module.engine.utils.*\\nimport org.apache.flink.api.common.functions.RuntimeContext\\nimport org.apache.flink.api.common.state.MapState\\nimport org.apache.flink.api.common.state.MapStateDescriptor\\nimport org.apache.flink.api.common.state.ValueState\\nimport org.apache.flink.api.common.state.ValueStateDescriptor\\nimport org.apache.flink.api.common.typeinfo.Types\\nimport org.apache.flink.api.java.tuple.Tuple2\\nimport org.apache.flink.util.Collector\\nimport org.apache.flink.util.StringUtils\\nimport org.slf4j.Logger\\nimport org.slf4j.LoggerFactory\\n/**\\n * 运算机one\\n */\\nclass ProcessorOne implements Processor {\\n\\n    private static final Logger log = LoggerFactory.getLogger(ProcessorOne.class)\\n\\n    /**\\n     * smallValue（窗口步长）: key为eventField,value为eventValue和最新的EventKafkaDTO\\n     */\\n    private MapState<String, Tuple2<Long, KafkaEventDTO>> smallMapState\\n    /**\\n     * 记录对应eventField是否已经初始化过（注意不要使用ListState，它查找指定元素的性能很差）\\n     */\\n    private MapState<String, Boolean> smallInitMapState\\n    /**\\n     * bigValue（窗口大小）: key为eventField，小map的key为时间戳，小map的value为一个一个步长的eventValue累加值和最新的EventKafkaDTO\\n     */\\n    private MapState<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapState\\n    /**\\n     * 对应 keyCode + keyValue 最近一次预警时间\\n     */\\n    private ValueState<Long> lastWarningTimeState\\n\\n    /**\\n     * 初始化方法，用于在运行时上下文中注册各种状态\\n     *\\n     * @param runtimeContext 运行时上下文，用于访问状态和其它运行时设施\\n     * @param ruleInfoDTO 规则信息数据传输对象，包含规则特定的元数据\\n     * @throws Exception 如果初始化过程中发生错误则抛出异常\\n     */\\n    @Override\\n    void init(RuntimeContext runtimeContext, RuleInfoDTO ruleInfoDTO) throws Exception {\\n        String ruleCode = ruleInfoDTO.getRuleCode()\\n        Long version = ruleInfoDTO.getVersion()\\n        // 状态变量注册使用 ruleCode 作为后缀，以防止不同规则使用相同的模型导致状态变量数据冲突覆盖\\n        smallMapState = runtimeContext.getMapState(\\n                new MapStateDescriptor<>(\\n                        \\\"smallMapState_${ruleCode}_${version}\\\", Types.STRING,\\n                        Types.TUPLE(Types.LONG, Types.POJO(KafkaEventDTO.class))\\n                )\\n        )\\n        smallInitMapState = runtimeContext.getMapState(\\n                new MapStateDescriptor<>(\\\"smallInitMapState_${ruleCode}_${version}\\\", Types.STRING, Types.BOOLEAN)\\n        )\\n        bigMapState = runtimeContext.getMapState(\\n                new MapStateDescriptor<>(\\\"bigMapState_${ruleCode}_${version}\\\", Types.STRING,\\n                        Types.MAP(Types.LONG, Types.TUPLE(Types.LONG, Types.POJO(KafkaEventDTO.class))))\\n        )\\n        lastWarningTimeState = runtimeContext.getState(\\n                new ValueStateDescriptor<>(\\\"lastWarningTimeState_${ruleCode}_${version}\\\", Types.LONG)\\n        )\\n    }\\n\\n    /**\\n     * 处理元素事件，根据给定的规则信息和Kafka事件进行处理\\n     *\\n     * @param currentEventTimestamp 时间戳，用于处理的时间参考\\n     * @param ruleInfoDTO 规则信息数据传输对象，包含规则的详细信息\\n     * @param kafkaEventDTO Kafka事件数据传输对象，包含事件的详细信息\\n     * @param out 用于输出处理结果的收集器\\n     * @throws Exception 如果处理过程中遇到任何错误，则抛出异常\\n     */\\n    @Override\\n    void processElement(long currentEventTimestamp, RuleInfoDTO ruleInfoDTO, KafkaEventDTO kafkaEventDTO) throws Exception {\\n        if (Objects.isNull(ruleInfoDTO)) {\\n            throw new BusinessException(\\\"运算机 ruleInfoDTO 必须非空\\\")\\n        }\\n        if (!Objects.equals(ruleInfoDTO.getRuleStatus(), CommonStatusEnum.ONLINE.getCode())\\n                && !Objects.equals(ruleInfoDTO.getRuleStatus(), CommonStatusEnum.OFFLINE_PENDING.getCode())) {\\n            log.warn(\\\"加载到运算机池中的规则状态必须为\'已上线\'或\'下线待审核\'！规则编号：{}\\\", ruleInfoDTO.getRuleCode())\\n            return\\n        }\\n        // 事件与规则渠道匹配不上，则直接跳过\\n        if (!Objects.equals(kafkaEventDTO.getChannel(), ruleInfoDTO.getChannel())) {\\n            return\\n        }\\n        // 事件与规则目标匹配不上，则直接跳过\\n        if (!Objects.equals(kafkaEventDTO.getTargetField(), ruleInfoDTO.getTargetField())) {\\n            return\\n        }\\n        // 获取规则条件\\n        List<RuleCondDTO> condGroupList = ruleInfoDTO.getRuleCondGroup()\\n        if (condGroupList == null || condGroupList.isEmpty()) {\\n            throw new BusinessException(\\\"运算机 condGroupList 必须非空\\\")\\n        }\\n        // 此模型仅支持条件为周期类型的规则\\n        for (RuleCondDTO condGroupDTO in condGroupList) {\\n            String type = condGroupDTO.getCondType()\\n            if (!Objects.equals(type, RuleCondTypeEnum.PERIODIC.getCode())) {\\n                log.warn(\\\"ProcessorOne 模型仅支持条件为周期类型的规则！规则编号：{}\\\", ruleInfoDTO.getRuleCode())\\n                return\\n            }\\n        }\\n        // 计算规则条件值\\n        processRuleCondValue(currentEventTimestamp, condGroupList, kafkaEventDTO)\\n    }\\n\\n    /**\\n     * 处理规则条件值\\n     *\\n     * 该方法主要用于处理一组规则条件DTO，通过与Kafka事件DTO进行匹配来更新状态值\\n     * 如果规则条件跨越历史时间段，则需要从Redis中获取历史事件值，并进行初始化\\n     *\\n     * @param currentEventTimestamp 时间戳，用于非跨历史时间段的事件匹配\\n     * @param ruleCondDtoGroup 规则条件DTO列表\\n     * @param kafkaEventDTO Kafka事件DTO\\n     */\\n    private void processRuleCondValue(long currentEventTimestamp, List<RuleCondDTO> ruleCondDtoGroup, KafkaEventDTO kafkaEventDTO) {\\n        for (RuleCondDTO ruleCondDTO : ruleCondDtoGroup) {\\n            // 事件与规则中的事件编号匹配不上，则直接跳过\\n            if (!Objects.equals(kafkaEventDTO.getEventField(), ruleCondDTO.getEventField())) {\\n                // 事件编号匹配不上，则直接跳过\\n                continue\\n            }\\n            // 进行事件属性匹配\\n            List<RuleEventAttrValueDTO> ruleEventAttrValueGroup = ruleCondDTO.getRuleEventAttrValueGroup()\\n            boolean eventAttributeMatchResult = matchEventAttribute(ruleEventAttrValueGroup, kafkaEventDTO)\\n            if (!eventAttributeMatchResult) {\\n                // 事件属性匹配不上，则直接跳过\\n                continue\\n            }\\n            // 状态值防空\\n            if (smallMapState.get(kafkaEventDTO.getEventField()) == null) {\\n                smallMapState.put(kafkaEventDTO.getEventField(), Tuple2.of(0L, kafkaEventDTO))\\n            }\\n            if (ruleCondDTO.getCrossHistory()) { //跨历史时间段\\n                String crossHistoryTimeline = ruleCondDTO.getCrossHistoryTimeline()\\n                // 因为跨历史时间段的规则条件需要处理历史缓存的数据，而历史缓存的数据可能过多，\\n                // 所以需要根据历史截止点进行过滤，仅需要大于历史截止点的数据\\n                if (kafkaEventDTO.getEventTime()\\n                        <= DateUtil.convertString2Timestamp(crossHistoryTimeline)) {\\n                    continue\\n                }\\n                // 因为跨历史时间段的规则条件需要从redis中获取doris中历史事件值，\\n                // 所以检查当前值是否已经通过redis初始化后，防止重复初始化\\n                if (!smallInitMapState.contains(kafkaEventDTO.getEventField())) {\\n                    // 如果为跨历史时间段的，且还没有初始化，则需要从redis中获取初始值\\n                    // （注意：Groovy字符串拼接的方式很麻烦，故使用StringBuilder）\\n                    String redisKey = buildRedisKey(ruleCondDTO)\\n                    String redisHashKey = buildRedisHashKey(kafkaEventDTO)\\n                    // 注意：因为上面获取历史缓存数据时，使用的是 <= 所以 redis 存储值时查询 doris 要包含历史截至时间点\\n                    String initValue = RedisUtil.hget(redisKey, redisHashKey)\\n                    if (StringUtils.isNullOrWhitespaceOnly(initValue)) {\\n                        throw new BusinessException(\\n                                StringUtil.format(\\\"从redis获取初始值必须非空, redisKey:{}, hashKey: {}\\\", redisKey, redisHashKey)\\n                        )\\n                    }\\n                    smallMapState.put(kafkaEventDTO.getEventField(), Tuple2.of(Long.parseLong(initValue), kafkaEventDTO))\\n                    smallInitMapState.put(kafkaEventDTO.getEventField(), true)\\n                }\\n                // 从redis初始化值后，正常处理数据\\n                Tuple2<Long, KafkaEventDTO> currentTuple = smallMapState.get(kafkaEventDTO.getEventField())\\n                Long newValue = currentTuple.f0 + Long.parseLong(kafkaEventDTO.getEventValue())\\n                smallMapState.put(kafkaEventDTO.getEventField(), Tuple2.of(newValue, kafkaEventDTO))\\n            } else { // 非跨历史时间段\\n                // 对于非跨历史时间段，只处理当前一条数据，不需要处理历史缓存数据\\n                if (kafkaEventDTO.getEventTime() != currentEventTimestamp) {\\n                    continue\\n                }\\n                Tuple2<Long, KafkaEventDTO> currentTuple = smallMapState.get(kafkaEventDTO.getEventField())\\n                Long newValue = currentTuple.f0 + Long.parseLong(kafkaEventDTO.getEventValue())\\n                smallMapState.put(kafkaEventDTO.getEventField(), Tuple2.of(newValue, kafkaEventDTO))\\n            }\\n        }\\n    }\\n\\n\\n    /**\\n     * 构建Redis的哈希键\\n     */\\n    private String buildRedisHashKey(KafkaEventDTO kafkaEventDTO) {\\n        String targetField = kafkaEventDTO.getTargetField()\\n        String targetValue = kafkaEventDTO.getTargetValue()\\n        return new StringBuilder()\\n                .append(targetField)\\n                .append(RedisKeyConstants.REDIS_KEY_SPLIT)\\n                .append(targetValue).toString()\\n    }\\n\\n    /**\\n     * 构建Redis的key\\n     */\\n    private String buildRedisKey(RuleCondDTO ruleCondDTO) {\\n        return new StringBuilder()\\n                .append(RedisKeyConstants.REDIS_KEY_PREFIX)\\n                .append(RedisKeyConstants.REDIS_KEY_SPLIT)\\n                .append(RedisKeyConstants.DORIS_EVENT_HISTORY_VALUE)\\n                .append(RedisKeyConstants.REDIS_KEY_SPLIT)\\n                .append(ruleCondDTO.getRuleCode())\\n                .append(RedisKeyConstants.REDIS_KEY_SPLIT)\\n                .append(ruleCondDTO.getEventField())\\n    }\\n\\n    /**\\n     * 匹配规则事件属性与Kafka事件属性是否符合\\n     *\\n     * 此方法的目的是为了验证给定的Kafka事件是否满足规则事件中定义的所有属性条件\\n     * 它通过比较规则事件属性和Kafka事件属性来确定两者是否匹配\\n     *\\n     * @param ruleEventDTO 规则事件DTO，包含规则事件的详细信息，包括事件属性\\n     * @param kafkaEventDTO Kafka事件DTO，包含Kafka事件的详细信息，包括事件属性\\n     * @return boolean 如果Kafka事件属性与规则事件属性完全匹配，则返回true；否则返回false\\n     */\\n    private boolean matchEventAttribute(List<RuleEventAttrValueDTO> ruleEventAttrValueGroup, KafkaEventDTO kafkaEventDTO) {\\n        if (CollectionUtil.isEmptyOrContainsNulls(ruleEventAttrValueGroup)) {\\n            // 规则中不包含事件属性相关的配置，则表明不需要进行事件属性匹配，直接跳过即可\\n            return true\\n        }\\n        // 逐一便利验证事件属性\\n        for (RuleEventAttrValueDTO ruleEventAttrValueDTO in ruleEventAttrValueGroup) {\\n            String attrValue = ruleEventAttrValueDTO.getAttrValue()\\n            if (StringUtils.isNullOrWhitespaceOnly(attrValue)) {\\n                // 规则中不包含事件属性值相关的配置，则表明不需要进行事件属性值匹配，直接跳过即可\\n                continue\\n            }\\n            String attrField = ruleEventAttrValueDTO.getAttrField()\\n            Map<String, String> kafkaEventAttrMap = kafkaEventDTO.getEventAttrMap()\\n            if (CollectionUtil.isEmpty(kafkaEventAttrMap)) {\\n                // 规则包含事件属性配置，但是kafka数据事件属性map为空，故直接判定为不符合规则要求\\n                log.warn(\\\"规则包含事件属性配置，但是kafka数据事件属性map为空，故直接判定为不符合规则要求！\\\" +\\n                        \\\"规则事件属性信息:{}, kafka事件信息:{}\\\", ruleEventAttrValueDTO, kafkaEventDTO)\\n                return false\\n            }\\n            if (!kafkaEventAttrMap.containsKey(attrField)) {\\n                // kafka事件属性不包含规则中事件属性，则表明不符合匹配\\n                log.warn(\\\"kafka数据事件属性map并不包含规则配置的事件属性Field，故直接判定为不符合规则要求！\\\" +\\n                        \\\"规则事件属性信息:{}, kafka事件信息:{}\\\", ruleEventAttrValueDTO, kafkaEventDTO)\\n                return false\\n            }\\n            String kafkaEventAttributeValue = kafkaEventAttrMap.get(attrField)\\n            if (Objects.isNull(kafkaEventAttributeValue)) {\\n                // kafka事件中对于规则中事件属性值为空，则表明不符合匹配\\n                return false\\n            }\\n            // 比较kafka中属性值与规则中属性值\\n            boolean isMatch = RuleEventAttrCompUtil.compareValues(ruleEventAttrValueDTO, kafkaEventDTO)\\n            if (!isMatch) {\\n                // kafka事件属性值与规则事件属性值不相等，则表明不符合匹配\\n                return false\\n            }\\n        }\\n        // 所有事件属性都匹配，则表明符合匹配\\n        return true\\n    }\\n\\n    /**\\n     * 定时器触发时执行的方法\\n     *\\n     * @param timestamp 时间戳，表示当前时间\\n     * @param ruleInfoDTO 规则信息DTO，包含规则相关数据\\n     * @param out 输出收集器，用于收集和输出预警信息\\n     * @throws Exception 可能抛出的异常\\n     */\\n    @Override\\n    boolean onTimer(long timestamp, String currentKey, RuleInfoDTO ruleInfoDTO, Collector<AlertMessageDTO> out) throws Exception {\\n        if (Objects.isNull(ruleInfoDTO)) {\\n            throw new BusinessException(\\\"运算机 ruleInfoDTO 必须非空\\\")\\n        }\\n        // 获取规则条件\\n        List<RuleCondDTO> groupGroup = ruleInfoDTO.getRuleCondGroup()\\n        if (groupGroup == null || groupGroup.isEmpty()) {\\n            throw new BusinessException(\\\"运算机 groupGroup 必须非空\\\")\\n        }\\n        // 将规则条件根据事件编号存储到map中，方便后续操作\\n        Map<String, RuleCondDTO> ruleConditionMapByEventField = new HashMap<>()\\n        for (RuleCondDTO ruleCondDTO : groupGroup) {\\n            ruleConditionMapByEventField.put(ruleCondDTO.getEventField(), ruleCondDTO)\\n        }\\n        // 将每个事件窗口步长数据集累加的值，添加到窗口大小数据集中bigMapState中\\n        updateBigMapWithSmallMap(timestamp)\\n        // 清理窗口大小之外的数据\\n        cleanupWindowData(timestamp, ruleConditionMapByEventField)\\n        // 判断是否触发规则事件阈值\\n        boolean eventResult = evaluateEventThresholds(ruleConditionMapByEventField, ruleInfoDTO)\\n        // 根据规则中事件条件表达式组合判断事件结果 与预警频率 判断否是触发预警\\n        if (lastWarningTimeState.value() == null) {\\n            lastWarningTimeState.update(0L)\\n        }\\n        // 获取预警间隔时间，单位为毫秒\\n        long alertInterval = TimeUtil.toMillis(\\n                ruleInfoDTO.getAlertIntervalValue(), TimeUnitEnum.fromEnUnit(ruleInfoDTO.getAlertIntervalUnit())\\n        )\\n        // 触发结果为true，且当前时间减去上次预警时间大于预警间隔时间，则进行预警\\n        if (eventResult && (timestamp - lastWarningTimeState.value() >= alertInterval)) {\\n            lastWarningTimeState.update(timestamp)\\n            // 进行预警信息拼接组合\\n            String finalWarnMessage = TemplateUtil.replacePlaceholders(\\n                    ruleInfoDTO.getAlertMessage(),\\n                    ruleInfoDTO,\\n                    getLatestEventKafkaDto(),\\n                    getProcessorDto()\\n            )\\n            AlertMessageDTO alertMessageDTO = AlertMessageDTO.builder()\\n                    .channel(ruleInfoDTO.getChannel())\\n                    .ruleCode(ruleInfoDTO.getRuleCode())\\n                    .alertMessage(finalWarnMessage)\\n                    .alertTime(DateUtil.convertTimestamp2LocalDateTime(System.currentTimeMillis()))\\n                    .build()\\n            log.warn(\\\"当前Key: {}, 最终推送的预警信息内容：{}\\\", currentKey, alertMessageDTO)\\n            out.collect(alertMessageDTO)\\n        }\\n        // 调试使用，待删除\\n        logBigMapState(currentKey, ruleInfoDTO.getRuleCode(), ruleConditionMapByEventField.keySet(), bigMapState)\\n        return hasActiveEvents()\\n    }\\n\\n    /**\\n     * 检查是否存在活跃的事件\\n     * 该方法用于遍历一个大的状态映射，以确定其中是否包含活跃的Kafka事件\\n     *\\n     * @return boolean - 如果存在活跃的事件，则返回true；否则返回false\\n     */\\n    private boolean hasActiveEvents() {\\n        boolean result = false\\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueMap = bigMapEntry.getValue()\\n            if (!CollectionUtil.isEmpty(timestampAndEventValueMap)) {\\n                result = true\\n                break\\n            }\\n        }\\n        result\\n    }\\n\\n    /**\\n     * 判断是否触发规则事件阈值。\\n     *\\n     * <p>此方法遍历 `bigMapState` 中的所有事件代码及其对应的时间戳和事件值累加，对每个事件代码\\n     * 的累加值与预定义的阈值进行比较。如果某个事件代码的累加值超过其阈值，则在结果映射中记录为 `true`。\\n     * 最后，根据 `ruleInfoDTO` 中指定的组合条件操作符（如 AND/OR）评估所有事件代码的结果，从而确定\\n     * 是否整体满足触发规则的条件。\\n     *\\n     * @param ruleConditionMapByEventField 按事件代码分组的规则条件映射，每个事件代码对应一个 `RuleConditionDTO`\\n     * @param ruleInfoDTO 规则信息数据传输对象，包含组合条件操作符等规则配置\\n     * @return 如果根据组合条件操作符评估后满足规则阈值条件，返回 `true`；否则返回 `false`\\n     * @throws Exception 在评估过程中发生任何异常时抛出\\n     */\\n    private boolean evaluateEventThresholds(Map<String, RuleCondDTO> ruleConditionMapByEventField,\\n                                            RuleInfoDTO ruleInfoDTO) throws Exception {\\n        Map<String, Boolean> eventFieldAndWarnResult = new HashMap<>()\\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\\n            String eventField = bigMapEntry.getKey()\\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueKafkaDtoMap = bigMapEntry.getValue()\\n            long eventValueSum = timestampAndEventValueKafkaDtoMap.values().stream()\\n                    .map(o -> o.f0)\\n                    .mapToLong(Long::longValue)\\n                    .sum()\\n            RuleCondDTO ruleCondDTO = ruleConditionMapByEventField.get(eventField)\\n            if (ruleCondDTO != null) {\\n                Long eventThreshold = ruleCondDTO.getThreshold()\\n                eventFieldAndWarnResult.put(eventField, eventValueSum > eventThreshold)\\n            }\\n        }\\n        boolean eventResult = evaluateEventResults(eventFieldAndWarnResult, ruleInfoDTO.getRuleCondCombOp())\\n        return eventResult\\n    }\\n\\n    /**\\n     * 聚合 bigMapState 中的事件值并构建 ProcessorDTO 对象。\\n     *\\n     * <p>该方法遍历 bigMapState，其中每个键为 eventField，值为一个包含时间戳和对应\\n     * Tuple2<Long, EventKafkaDTO> 的映射。对于每个 eventFiled，方法会将所有时间戳\\n     * 下的 eventValue（Tuple2 中的第一个值）进行累加，生成一个 eventField 与其\\n     * 累加值的映射。最后，基于这些聚合结果构建并返回一个包含 eventFiledAndValueSumMap 的 ProcessorDTO 对象。</p>\\n     *\\n     * @return 包含每个 eventFiled 对应 eventValue 累加值的 ProcessorDTO 对象\\n     * @throws Exception 如果在处理过程中发生错误\\n     */\\n    private ProcessorDTO getProcessorDto() throws Exception {\\n        Map<String, Long> eventFiledAndValueSumMap = new HashMap<>()\\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\\n            String eventField = bigMapEntry.getKey()\\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueKafkaDtoMap = bigMapEntry.getValue()\\n            long eventValueSum = timestampAndEventValueKafkaDtoMap.values().stream()\\n                    .map(o -> o.f0)\\n                    .mapToLong(Long::longValue)\\n                    .sum()\\n            eventFiledAndValueSumMap.put(eventField, eventValueSum)\\n        }\\n        ProcessorDTO processorDTO = ProcessorDTO.builder()\\n                .eventFieldAndValueSumMap(eventFiledAndValueSumMap)\\n                .build()\\n        return processorDTO\\n    }\\n\\n\\n    /**\\n     * 从所有事件条件累积的值流中检索最新的 Kafka 事件数据。\\n     *\\n     * <p>此方法遍历 `bigMapState` 中存储的所有事件数据，查找具有最大时间戳的 `EventKafkaDTO` 对象，\\n     * 并返回该最新的事件数据。\\n     *\\n     * @return 最新的 {@link KafkaEventDTO} 对象，如果没有事件数据则返回 {@code null}\\n     * @throws Exception 如果在遍历过程中发生异常\\n     */\\n    private KafkaEventDTO getLatestEventKafkaDto() throws Exception {\\n        // 初始化变量，用于存储最新的 EventKafkaDTO 和对应的最大时间戳\\n        KafkaEventDTO latestEventKafkaDTO = null\\n        Long maxTimestamp = Long.MIN_VALUE\\n\\n        // 遍历 bigMapState 中的每一个大键（eventField）及其对应的内部映射\\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\\n            // 获取当前 eventField 对应的时间戳与事件数据的映射\\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueKafkaDtoMap = bigMapEntry.getValue()\\n\\n            // 获取当前映射中的所有条目（时间戳与事件数据对）\\n            Set<Map.Entry<Long, Tuple2<Long, KafkaEventDTO>>> entrySet = timestampAndEventValueKafkaDtoMap.entrySet()\\n\\n            // 遍历当前 eventField 下的所有时间戳和事件数据对\\n            for (Map.Entry<Long, Tuple2<Long, KafkaEventDTO>> entry : entrySet) {\\n                Long currentTimestamp = entry.getKey() // 当前条目的时间戳\\n                Tuple2<Long, KafkaEventDTO> value = entry.getValue() // 包含累加值和事件数据的元组\\n\\n                // 如果当前时间戳大于已记录的最大时间戳，则更新最大时间戳和最新的事件数据\\n                if (currentTimestamp > maxTimestamp) {\\n                    maxTimestamp = currentTimestamp\\n                    latestEventKafkaDTO = value.f1 // 获取元组中的 EventKafkaDTO 对象\\n                }\\n            }\\n        }\\n\\n        // 返回找到的最新的 EventKafkaDTO 对象\\n        return latestEventKafkaDTO\\n    }\\n\\n\\n    /**\\n     * 将每个事件窗口步长数据集累加的值，添加到窗口大小数据集中bigMapState中\\n     */\\n    private void updateBigMapWithSmallMap(long timestamp) throws Exception {\\n        for (Map.Entry<String, Tuple2<Long, KafkaEventDTO>> smallMapEntry : smallMapState.entries()) {\\n            String eventField = smallMapEntry.getKey()\\n            Tuple2<Long, KafkaEventDTO> eventValueAndKafkaDtoTuple2 = smallMapEntry.getValue()\\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueMap = bigMapState.get(eventField)\\n            if (timestampAndEventValueMap == null || timestampAndEventValueMap.isEmpty()) {\\n                timestampAndEventValueMap = new HashMap<>()\\n            }\\n            timestampAndEventValueMap.put(timestamp, eventValueAndKafkaDtoTuple2)\\n            bigMapState.put(eventField, timestampAndEventValueMap)\\n        }\\n        // 当前窗口步长的数据已经添加到窗口中了，清空状态\\n        smallMapState.clear()\\n    }\\n\\n    /**\\n     * 清理窗口大小之外的数据\\n     */\\n    private void cleanupWindowData(long timestamp, Map<String, RuleCondDTO> ruleConditionMapByEventField) throws Exception {\\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\\n            String eventField = bigMapEntry.getKey()\\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueMap = bigMapEntry.getValue()\\n            RuleCondDTO ruleCondDTO = ruleConditionMapByEventField.get(eventField)\\n            if (Objects.isNull(ruleCondDTO)) {\\n                log.warn(\\\"清理窗口大小之外的数据时，存在规则条件中不存在的数据\\\")\\n                continue\\n            }\\n            long windowSize = TimeUtil.toMillis(ruleCondDTO.getWindowValue(), TimeUnitEnum.fromEnUnit(ruleCondDTO.getWindowUnit()))\\n            long windowThresholdTime = timestamp - windowSize\\n            Iterator<Map.Entry<Long, Tuple2<Long, KafkaEventDTO>>> iterator = timestampAndEventValueMap.entrySet().iterator()\\n            while (iterator.hasNext()) {\\n                Map.Entry<Long, Tuple2<Long, KafkaEventDTO>> next = iterator.next()\\n                Long time = next.getKey()\\n                if (time <= windowThresholdTime) {\\n                    iterator.remove()\\n                }\\n            }\\n            bigMapState.put(eventField, timestampAndEventValueMap)\\n        }\\n    }\\n\\n    /**\\n     * 日志打印\\n     */\\n    private void logBigMapState(String currentKey, String ruleCode, Set<String> eventFieldList, MapState<String,\\n            Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapState) throws Exception {\\n        Map<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMap = new HashMap<>()\\n        Iterator<Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>>> iterator = bigMapState.iterator()\\n        while (iterator.hasNext()) {\\n            Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> next = iterator.next()\\n            bigMap.put(next.getKey(), next.getValue())\\n        }\\n        log.warn(\\\"ProcessorOne对象onTimer方法结束 currentKey={}, ruleCode={}, eventFieldList={}, bigMapState={}\\\",\\n                currentKey, ruleCode, JsonUtil.toJsonString(eventFieldList), JsonUtil.toJsonString(bigMap))\\n    }\\n\\n    /**\\n     * 评估事件结果，根据给定的条件操作符返回最终结果。\\n     *\\n     * @param eventFieldAndWarnResult 包含事件代码及其对应的警告结果的映射\\n     * @param conditionOperator 条件操作符，支持 AND 和 OR\\n     * @return 根据条件操作符计算后的最终结果（true 或 false）\\n     */\\n    boolean evaluateEventResults(Map<String, Boolean> eventFieldAndWarnResult, String conditionOperator) {\\n        // 检查输入是否为 null 或为空\\n        if (eventFieldAndWarnResult == null || eventFieldAndWarnResult.isEmpty()) {\\n            return false\\n        }\\n\\n        // 如果只有一个元素，直接返回该元素的值\\n        if (eventFieldAndWarnResult.size() == 1) {\\n            return eventFieldAndWarnResult.values().iterator().next()\\n        }\\n\\n        // 确定操作符类型\\n        RuleCondCombOpEnum opEnum = RuleCondCombOpEnum.fromCode(conditionOperator)\\n\\n        // 初始化结果，根据操作符类型\\n        boolean result\\n        if (opEnum == RuleCondCombOpEnum.AND) {\\n            result = true // 对于 AND，初始值为 true\\n            for (Boolean eventResult : eventFieldAndWarnResult.values()) {\\n                if (!eventResult) {\\n                    return false // 任何一个 false 都返回 false\\n                }\\n            }\\n        } else if (opEnum == RuleCondCombOpEnum.OR) {\\n            result = false // 对于 OR，初始值为 false\\n            for (Boolean eventResult : eventFieldAndWarnResult.values()) {\\n                if (eventResult) {\\n                    return true // 任何一个 true 都返回 true\\n                }\\n            }\\n        } else {\\n            throw new IllegalArgumentException(\\\"Unsupported condition operator: \\\" + conditionOperator)\\n        }\\n\\n        return result\\n    }\\n\\n}\\n\",\"ruleCode\":\"R1873910811026657280\",\"ruleCondGroup\":[{\"condCode\":\"R1873910811026657280_GAME_userId_lottery\",\"condType\":\"CYCLE\",\"crossHistory\":false,\"eventCode\":\"GAME_userId_lottery\",\"eventField\":\"lottery\",\"eventName\":\"游戏抽奖事件\",\"ruleCode\":\"R1873910811026657280\",\"threshold\":10,\"windowUnit\":\"分钟\",\"windowValue\":10}],\"ruleDesc\":\"游戏高频抽奖规则\",\"ruleName\":\"游戏高频抽奖\",\"ruleStatus\":\"ONLINE\",\"targetCode\":\"GAME_userId\",\"targetField\":\"userId\",\"targetName\":\"游戏用户id\",\"version\":3}',
        'system', NULL, '2025-01-04 18:12:50', NULL);

-- ----------------------------
-- Table structure for slr_rule_model
-- ----------------------------
DROP TABLE IF EXISTS `slr_rule_model`;
CREATE TABLE `slr_rule_model`
(
    `id`          bigint UNSIGNED                                        NOT NULL AUTO_INCREMENT COMMENT '自增主键ID',
    `model_code`  varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '模型编号',
    `model_name`  varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '模型名称',
    `model_desc`  varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '模型描述',
    `groovy`      text CHARACTER SET utf8mb4 COLLATE utf8mb4_bin         NULL COMMENT '运算机groovy代码',
    `creator`     varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '创建用户',
    `updater`     varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '更新用户',
    `create_time` datetime                                               NULL DEFAULT NULL COMMENT '创建时间',
    `update_time` datetime                                               NULL DEFAULT NULL COMMENT '创建时间',
    PRIMARY KEY (`id`) USING BTREE,
    UNIQUE INDEX `uk_model_code` (`model_code` ASC) USING BTREE
) ENGINE = InnoDB
  AUTO_INCREMENT = 2
  CHARACTER SET = utf8mb4
  COLLATE = utf8mb4_bin COMMENT = '风控规则模型表'
  ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of slr_rule_model
-- ----------------------------
INSERT INTO `slr_rule_model`
VALUES (1, 'M1873324910378618880', '模型运算机一', '支持多周期条件、事件属性过滤的规则模型',
        'package com.liboshuai.slr.module.engine.processor.impl\n\n\nimport com.liboshuai.slr.framework.common.constants.RedisKeyConstants\nimport com.liboshuai.slr.framework.common.enums.CommonStatusEnum\nimport com.liboshuai.slr.module.engine.dto.*\nimport com.liboshuai.slr.module.engine.enums.RuleCondCombOpEnum\nimport com.liboshuai.slr.module.engine.enums.RuleCondTypeEnum\nimport com.liboshuai.slr.module.engine.enums.TimeUnitEnum\nimport com.liboshuai.slr.module.engine.framework.exception.BusinessException\nimport com.liboshuai.slr.module.engine.processor.Processor\nimport com.liboshuai.slr.module.engine.utils.*\nimport org.apache.flink.api.common.functions.RuntimeContext\nimport org.apache.flink.api.common.state.MapState\nimport org.apache.flink.api.common.state.MapStateDescriptor\nimport org.apache.flink.api.common.state.ValueState\nimport org.apache.flink.api.common.state.ValueStateDescriptor\nimport org.apache.flink.api.common.typeinfo.Types\nimport org.apache.flink.api.java.tuple.Tuple2\nimport org.apache.flink.util.Collector\nimport org.apache.flink.util.StringUtils\nimport org.slf4j.Logger\nimport org.slf4j.LoggerFactory\n/**\n * 运算机one\n */\nclass ProcessorOne implements Processor {\n\n    private static final Logger log = LoggerFactory.getLogger(ProcessorOne.class)\n\n    /**\n     * smallValue（窗口步长）: key为eventField,value为eventValue和最新的EventKafkaDTO\n     */\n    private MapState<String, Tuple2<Long, KafkaEventDTO>> smallMapState\n    /**\n     * 记录对应eventField是否已经初始化过（注意不要使用ListState，它查找指定元素的性能很差）\n     */\n    private MapState<String, Boolean> smallInitMapState\n    /**\n     * bigValue（窗口大小）: key为eventField，小map的key为时间戳，小map的value为一个一个步长的eventValue累加值和最新的EventKafkaDTO\n     */\n    private MapState<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapState\n    /**\n     * 对应 keyCode + keyValue 最近一次预警时间\n     */\n    private ValueState<Long> lastWarningTimeState\n\n    /**\n     * 初始化方法，用于在运行时上下文中注册各种状态\n     *\n     * @param runtimeContext 运行时上下文，用于访问状态和其它运行时设施\n     * @param ruleInfoDTO 规则信息数据传输对象，包含规则特定的元数据\n     * @throws Exception 如果初始化过程中发生错误则抛出异常\n     */\n    @Override\n    void init(RuntimeContext runtimeContext, RuleInfoDTO ruleInfoDTO) throws Exception {\n        String ruleCode = ruleInfoDTO.getRuleCode()\n        Long version = ruleInfoDTO.getVersion()\n        // 状态变量注册使用 ruleCode 作为后缀，以防止不同规则使用相同的模型导致状态变量数据冲突覆盖\n        smallMapState = runtimeContext.getMapState(\n                new MapStateDescriptor<>(\n                        \"smallMapState_${ruleCode}_${version}\", Types.STRING,\n                        Types.TUPLE(Types.LONG, Types.POJO(KafkaEventDTO.class))\n                )\n        )\n        smallInitMapState = runtimeContext.getMapState(\n                new MapStateDescriptor<>(\"smallInitMapState_${ruleCode}_${version}\", Types.STRING, Types.BOOLEAN)\n        )\n        bigMapState = runtimeContext.getMapState(\n                new MapStateDescriptor<>(\"bigMapState_${ruleCode}_${version}\", Types.STRING,\n                        Types.MAP(Types.LONG, Types.TUPLE(Types.LONG, Types.POJO(KafkaEventDTO.class))))\n        )\n        lastWarningTimeState = runtimeContext.getState(\n                new ValueStateDescriptor<>(\"lastWarningTimeState_${ruleCode}_${version}\", Types.LONG)\n        )\n    }\n\n    /**\n     * 处理元素事件，根据给定的规则信息和Kafka事件进行处理\n     *\n     * @param currentEventTimestamp 时间戳，用于处理的时间参考\n     * @param ruleInfoDTO 规则信息数据传输对象，包含规则的详细信息\n     * @param kafkaEventDTO Kafka事件数据传输对象，包含事件的详细信息\n     * @param out 用于输出处理结果的收集器\n     * @throws Exception 如果处理过程中遇到任何错误，则抛出异常\n     */\n    @Override\n    void processElement(long currentEventTimestamp, RuleInfoDTO ruleInfoDTO, KafkaEventDTO kafkaEventDTO) throws Exception {\n        if (Objects.isNull(ruleInfoDTO)) {\n            throw new BusinessException(\"运算机 ruleInfoDTO 必须非空\")\n        }\n        if (!Objects.equals(ruleInfoDTO.getRuleStatus(), CommonStatusEnum.ONLINE.getCode())\n                && !Objects.equals(ruleInfoDTO.getRuleStatus(), CommonStatusEnum.OFFLINE_PENDING.getCode())) {\n            log.warn(\"加载到运算机池中的规则状态必须为\'已上线\'或\'下线待审核\'！规则编号：{}\", ruleInfoDTO.getRuleCode())\n            return\n        }\n        // 事件与规则渠道匹配不上，则直接跳过\n        if (!Objects.equals(kafkaEventDTO.getChannel(), ruleInfoDTO.getChannel())) {\n            return\n        }\n        // 事件与规则目标匹配不上，则直接跳过\n        if (!Objects.equals(kafkaEventDTO.getTargetField(), ruleInfoDTO.getTargetField())) {\n            return\n        }\n        // 获取规则条件\n        List<RuleCondDTO> condGroupList = ruleInfoDTO.getRuleCondGroup()\n        if (condGroupList == null || condGroupList.isEmpty()) {\n            throw new BusinessException(\"运算机 condGroupList 必须非空\")\n        }\n        // 此模型仅支持条件为周期类型的规则\n        for (RuleCondDTO condGroupDTO in condGroupList) {\n            String type = condGroupDTO.getCondType()\n            if (!Objects.equals(type, RuleCondTypeEnum.PERIODIC.getCode())) {\n                log.warn(\"ProcessorOne 模型仅支持条件为周期类型的规则！规则编号：{}\", ruleInfoDTO.getRuleCode())\n                return\n            }\n        }\n        // 计算规则条件值\n        processRuleCondValue(currentEventTimestamp, condGroupList, kafkaEventDTO)\n    }\n\n    /**\n     * 处理规则条件值\n     *\n     * 该方法主要用于处理一组规则条件DTO，通过与Kafka事件DTO进行匹配来更新状态值\n     * 如果规则条件跨越历史时间段，则需要从Redis中获取历史事件值，并进行初始化\n     *\n     * @param currentEventTimestamp 时间戳，用于非跨历史时间段的事件匹配\n     * @param ruleCondDtoGroup 规则条件DTO列表\n     * @param kafkaEventDTO Kafka事件DTO\n     */\n    private void processRuleCondValue(long currentEventTimestamp, List<RuleCondDTO> ruleCondDtoGroup, KafkaEventDTO kafkaEventDTO) {\n        for (RuleCondDTO ruleCondDTO : ruleCondDtoGroup) {\n            // 事件与规则中的事件编号匹配不上，则直接跳过\n            if (!Objects.equals(kafkaEventDTO.getEventField(), ruleCondDTO.getEventField())) {\n                // 事件编号匹配不上，则直接跳过\n                continue\n            }\n            // 进行事件属性匹配\n            List<RuleEventAttrValueDTO> ruleEventAttrValueGroup = ruleCondDTO.getRuleEventAttrValueGroup()\n            boolean eventAttributeMatchResult = matchEventAttribute(ruleEventAttrValueGroup, kafkaEventDTO)\n            if (!eventAttributeMatchResult) {\n                // 事件属性匹配不上，则直接跳过\n                continue\n            }\n            // 状态值防空\n            if (smallMapState.get(kafkaEventDTO.getEventField()) == null) {\n                smallMapState.put(kafkaEventDTO.getEventField(), Tuple2.of(0L, kafkaEventDTO))\n            }\n            if (ruleCondDTO.getCrossHistory()) { //跨历史时间段\n                String crossHistoryTimeline = ruleCondDTO.getCrossHistoryTimeline()\n                // 因为跨历史时间段的规则条件需要处理历史缓存的数据，而历史缓存的数据可能过多，\n                // 所以需要根据历史截止点进行过滤，仅需要大于历史截止点的数据\n                if (kafkaEventDTO.getEventTime()\n                        <= DateUtil.convertString2Timestamp(crossHistoryTimeline)) {\n                    continue\n                }\n                // 因为跨历史时间段的规则条件需要从redis中获取doris中历史事件值，\n                // 所以检查当前值是否已经通过redis初始化后，防止重复初始化\n                if (!smallInitMapState.contains(kafkaEventDTO.getEventField())) {\n                    // 如果为跨历史时间段的，且还没有初始化，则需要从redis中获取初始值\n                    // （注意：Groovy字符串拼接的方式很麻烦，故使用StringBuilder）\n                    String redisKey = buildRedisKey(ruleCondDTO)\n                    String redisHashKey = buildRedisHashKey(kafkaEventDTO)\n                    // 注意：因为上面获取历史缓存数据时，使用的是 <= 所以 redis 存储值时查询 doris 要包含历史截至时间点\n                    String initValue = RedisUtil.hget(redisKey, redisHashKey)\n                    if (StringUtils.isNullOrWhitespaceOnly(initValue)) {\n                        throw new BusinessException(\n                                StringUtil.format(\"从redis获取初始值必须非空, redisKey:{}, hashKey: {}\", redisKey, redisHashKey)\n                        )\n                    }\n                    smallMapState.put(kafkaEventDTO.getEventField(), Tuple2.of(Long.parseLong(initValue), kafkaEventDTO))\n                    smallInitMapState.put(kafkaEventDTO.getEventField(), true)\n                }\n                // 从redis初始化值后，正常处理数据\n                Tuple2<Long, KafkaEventDTO> currentTuple = smallMapState.get(kafkaEventDTO.getEventField())\n                Long newValue = currentTuple.f0 + Long.parseLong(kafkaEventDTO.getEventValue())\n                smallMapState.put(kafkaEventDTO.getEventField(), Tuple2.of(newValue, kafkaEventDTO))\n            } else { // 非跨历史时间段\n                // 对于非跨历史时间段，只处理当前一条数据，不需要处理历史缓存数据\n                if (kafkaEventDTO.getEventTime() != currentEventTimestamp) {\n                    continue\n                }\n                Tuple2<Long, KafkaEventDTO> currentTuple = smallMapState.get(kafkaEventDTO.getEventField())\n                Long newValue = currentTuple.f0 + Long.parseLong(kafkaEventDTO.getEventValue())\n                smallMapState.put(kafkaEventDTO.getEventField(), Tuple2.of(newValue, kafkaEventDTO))\n            }\n        }\n    }\n\n\n    /**\n     * 构建Redis的哈希键\n     */\n    private String buildRedisHashKey(KafkaEventDTO kafkaEventDTO) {\n        String targetField = kafkaEventDTO.getTargetField()\n        String targetValue = kafkaEventDTO.getTargetValue()\n        return new StringBuilder()\n                .append(targetField)\n                .append(RedisKeyConstants.REDIS_KEY_SPLIT)\n                .append(targetValue).toString()\n    }\n\n    /**\n     * 构建Redis的key\n     */\n    private String buildRedisKey(RuleCondDTO ruleCondDTO) {\n        return new StringBuilder()\n                .append(RedisKeyConstants.REDIS_KEY_PREFIX)\n                .append(RedisKeyConstants.REDIS_KEY_SPLIT)\n                .append(RedisKeyConstants.DORIS_EVENT_HISTORY_VALUE)\n                .append(RedisKeyConstants.REDIS_KEY_SPLIT)\n                .append(ruleCondDTO.getRuleCode())\n                .append(RedisKeyConstants.REDIS_KEY_SPLIT)\n                .append(ruleCondDTO.getEventField())\n    }\n\n    /**\n     * 匹配规则事件属性与Kafka事件属性是否符合\n     *\n     * 此方法的目的是为了验证给定的Kafka事件是否满足规则事件中定义的所有属性条件\n     * 它通过比较规则事件属性和Kafka事件属性来确定两者是否匹配\n     *\n     * @param ruleEventDTO 规则事件DTO，包含规则事件的详细信息，包括事件属性\n     * @param kafkaEventDTO Kafka事件DTO，包含Kafka事件的详细信息，包括事件属性\n     * @return boolean 如果Kafka事件属性与规则事件属性完全匹配，则返回true；否则返回false\n     */\n    private boolean matchEventAttribute(List<RuleEventAttrValueDTO> ruleEventAttrValueGroup, KafkaEventDTO kafkaEventDTO) {\n        if (CollectionUtil.isEmptyOrContainsNulls(ruleEventAttrValueGroup)) {\n            // 规则中不包含事件属性相关的配置，则表明不需要进行事件属性匹配，直接跳过即可\n            return true\n        }\n        // 逐一便利验证事件属性\n        for (RuleEventAttrValueDTO ruleEventAttrValueDTO in ruleEventAttrValueGroup) {\n            String attrValue = ruleEventAttrValueDTO.getAttrValue()\n            if (StringUtils.isNullOrWhitespaceOnly(attrValue)) {\n                // 规则中不包含事件属性值相关的配置，则表明不需要进行事件属性值匹配，直接跳过即可\n                continue\n            }\n            String attrField = ruleEventAttrValueDTO.getAttrField()\n            Map<String, String> kafkaEventAttrMap = kafkaEventDTO.getEventAttrMap()\n            if (CollectionUtil.isEmpty(kafkaEventAttrMap)) {\n                // 规则包含事件属性配置，但是kafka数据事件属性map为空，故直接判定为不符合规则要求\n                log.warn(\"规则包含事件属性配置，但是kafka数据事件属性map为空，故直接判定为不符合规则要求！\" +\n                        \"规则事件属性信息:{}, kafka事件信息:{}\", ruleEventAttrValueDTO, kafkaEventDTO)\n                return false\n            }\n            if (!kafkaEventAttrMap.containsKey(attrField)) {\n                // kafka事件属性不包含规则中事件属性，则表明不符合匹配\n                log.warn(\"kafka数据事件属性map并不包含规则配置的事件属性Field，故直接判定为不符合规则要求！\" +\n                        \"规则事件属性信息:{}, kafka事件信息:{}\", ruleEventAttrValueDTO, kafkaEventDTO)\n                return false\n            }\n            String kafkaEventAttributeValue = kafkaEventAttrMap.get(attrField)\n            if (Objects.isNull(kafkaEventAttributeValue)) {\n                // kafka事件中对于规则中事件属性值为空，则表明不符合匹配\n                return false\n            }\n            // 比较kafka中属性值与规则中属性值\n            boolean isMatch = RuleEventAttrCompUtil.compareValues(ruleEventAttrValueDTO, kafkaEventDTO)\n            if (!isMatch) {\n                // kafka事件属性值与规则事件属性值不相等，则表明不符合匹配\n                return false\n            }\n        }\n        // 所有事件属性都匹配，则表明符合匹配\n        return true\n    }\n\n    /**\n     * 定时器触发时执行的方法\n     *\n     * @param timestamp 时间戳，表示当前时间\n     * @param ruleInfoDTO 规则信息DTO，包含规则相关数据\n     * @param out 输出收集器，用于收集和输出预警信息\n     * @throws Exception 可能抛出的异常\n     */\n    @Override\n    boolean onTimer(long timestamp, String currentKey, RuleInfoDTO ruleInfoDTO, Collector<AlertMessageDTO> out) throws Exception {\n        if (Objects.isNull(ruleInfoDTO)) {\n            throw new BusinessException(\"运算机 ruleInfoDTO 必须非空\")\n        }\n        // 获取规则条件\n        List<RuleCondDTO> groupGroup = ruleInfoDTO.getRuleCondGroup()\n        if (groupGroup == null || groupGroup.isEmpty()) {\n            throw new BusinessException(\"运算机 groupGroup 必须非空\")\n        }\n        // 将规则条件根据事件编号存储到map中，方便后续操作\n        Map<String, RuleCondDTO> ruleConditionMapByEventField = new HashMap<>()\n        for (RuleCondDTO ruleCondDTO : groupGroup) {\n            ruleConditionMapByEventField.put(ruleCondDTO.getEventField(), ruleCondDTO)\n        }\n        // 将每个事件窗口步长数据集累加的值，添加到窗口大小数据集中bigMapState中\n        updateBigMapWithSmallMap(timestamp)\n        // 清理窗口大小之外的数据\n        cleanupWindowData(timestamp, ruleConditionMapByEventField)\n        // 判断是否触发规则事件阈值\n        boolean eventResult = evaluateEventThresholds(ruleConditionMapByEventField, ruleInfoDTO)\n        // 根据规则中事件条件表达式组合判断事件结果 与预警频率 判断否是触发预警\n        if (lastWarningTimeState.value() == null) {\n            lastWarningTimeState.update(0L)\n        }\n        // 获取预警间隔时间，单位为毫秒\n        long alertInterval = TimeUtil.toMillis(\n                ruleInfoDTO.getAlertIntervalValue(), TimeUnitEnum.fromEnUnit(ruleInfoDTO.getAlertIntervalUnit())\n        )\n        // 触发结果为true，且当前时间减去上次预警时间大于预警间隔时间，则进行预警\n        if (eventResult && (timestamp - lastWarningTimeState.value() >= alertInterval)) {\n            lastWarningTimeState.update(timestamp)\n            // 进行预警信息拼接组合\n            String finalWarnMessage = TemplateUtil.replacePlaceholders(\n                    ruleInfoDTO.getAlertMessage(),\n                    ruleInfoDTO,\n                    getLatestEventKafkaDto(),\n                    getProcessorDto()\n            )\n            AlertMessageDTO alertMessageDTO = AlertMessageDTO.builder()\n                    .channel(ruleInfoDTO.getChannel())\n                    .ruleCode(ruleInfoDTO.getRuleCode())\n                    .alertMessage(finalWarnMessage)\n                    .alertTime(DateUtil.convertTimestamp2LocalDateTime(System.currentTimeMillis()))\n                    .build()\n            log.warn(\"当前Key: {}, 最终推送的预警信息内容：{}\", currentKey, alertMessageDTO)\n            out.collect(alertMessageDTO)\n        }\n        // 调试使用，待删除\n        logBigMapState(currentKey, ruleInfoDTO.getRuleCode(), ruleConditionMapByEventField.keySet(), bigMapState)\n        return hasActiveEvents()\n    }\n\n    /**\n     * 检查是否存在活跃的事件\n     * 该方法用于遍历一个大的状态映射，以确定其中是否包含活跃的Kafka事件\n     *\n     * @return boolean - 如果存在活跃的事件，则返回true；否则返回false\n     */\n    private boolean hasActiveEvents() {\n        boolean result = false\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueMap = bigMapEntry.getValue()\n            if (!CollectionUtil.isEmpty(timestampAndEventValueMap)) {\n                result = true\n                break\n            }\n        }\n        result\n    }\n\n    /**\n     * 判断是否触发规则事件阈值。\n     *\n     * <p>此方法遍历 `bigMapState` 中的所有事件代码及其对应的时间戳和事件值累加，对每个事件代码\n     * 的累加值与预定义的阈值进行比较。如果某个事件代码的累加值超过其阈值，则在结果映射中记录为 `true`。\n     * 最后，根据 `ruleInfoDTO` 中指定的组合条件操作符（如 AND/OR）评估所有事件代码的结果，从而确定\n     * 是否整体满足触发规则的条件。\n     *\n     * @param ruleConditionMapByEventField 按事件代码分组的规则条件映射，每个事件代码对应一个 `RuleConditionDTO`\n     * @param ruleInfoDTO 规则信息数据传输对象，包含组合条件操作符等规则配置\n     * @return 如果根据组合条件操作符评估后满足规则阈值条件，返回 `true`；否则返回 `false`\n     * @throws Exception 在评估过程中发生任何异常时抛出\n     */\n    private boolean evaluateEventThresholds(Map<String, RuleCondDTO> ruleConditionMapByEventField,\n                                            RuleInfoDTO ruleInfoDTO) throws Exception {\n        Map<String, Boolean> eventFieldAndWarnResult = new HashMap<>()\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\n            String eventField = bigMapEntry.getKey()\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueKafkaDtoMap = bigMapEntry.getValue()\n            long eventValueSum = timestampAndEventValueKafkaDtoMap.values().stream()\n                    .map(o -> o.f0)\n                    .mapToLong(Long::longValue)\n                    .sum()\n            RuleCondDTO ruleCondDTO = ruleConditionMapByEventField.get(eventField)\n            if (ruleCondDTO != null) {\n                Long eventThreshold = ruleCondDTO.getThreshold()\n                eventFieldAndWarnResult.put(eventField, eventValueSum > eventThreshold)\n            }\n        }\n        boolean eventResult = evaluateEventResults(eventFieldAndWarnResult, ruleInfoDTO.getRuleCondCombOp())\n        return eventResult\n    }\n\n    /**\n     * 聚合 bigMapState 中的事件值并构建 ProcessorDTO 对象。\n     *\n     * <p>该方法遍历 bigMapState，其中每个键为 eventField，值为一个包含时间戳和对应\n     * Tuple2<Long, EventKafkaDTO> 的映射。对于每个 eventFiled，方法会将所有时间戳\n     * 下的 eventValue（Tuple2 中的第一个值）进行累加，生成一个 eventField 与其\n     * 累加值的映射。最后，基于这些聚合结果构建并返回一个包含 eventFiledAndValueSumMap 的 ProcessorDTO 对象。</p>\n     *\n     * @return 包含每个 eventFiled 对应 eventValue 累加值的 ProcessorDTO 对象\n     * @throws Exception 如果在处理过程中发生错误\n     */\n    private ProcessorDTO getProcessorDto() throws Exception {\n        Map<String, Long> eventFiledAndValueSumMap = new HashMap<>()\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\n            String eventField = bigMapEntry.getKey()\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueKafkaDtoMap = bigMapEntry.getValue()\n            long eventValueSum = timestampAndEventValueKafkaDtoMap.values().stream()\n                    .map(o -> o.f0)\n                    .mapToLong(Long::longValue)\n                    .sum()\n            eventFiledAndValueSumMap.put(eventField, eventValueSum)\n        }\n        ProcessorDTO processorDTO = ProcessorDTO.builder()\n                .eventFieldAndValueSumMap(eventFiledAndValueSumMap)\n                .build()\n        return processorDTO\n    }\n\n\n    /**\n     * 从所有事件条件累积的值流中检索最新的 Kafka 事件数据。\n     *\n     * <p>此方法遍历 `bigMapState` 中存储的所有事件数据，查找具有最大时间戳的 `EventKafkaDTO` 对象，\n     * 并返回该最新的事件数据。\n     *\n     * @return 最新的 {@link KafkaEventDTO} 对象，如果没有事件数据则返回 {@code null}\n     * @throws Exception 如果在遍历过程中发生异常\n     */\n    private KafkaEventDTO getLatestEventKafkaDto() throws Exception {\n        // 初始化变量，用于存储最新的 EventKafkaDTO 和对应的最大时间戳\n        KafkaEventDTO latestEventKafkaDTO = null\n        Long maxTimestamp = Long.MIN_VALUE\n\n        // 遍历 bigMapState 中的每一个大键（eventField）及其对应的内部映射\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\n            // 获取当前 eventField 对应的时间戳与事件数据的映射\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueKafkaDtoMap = bigMapEntry.getValue()\n\n            // 获取当前映射中的所有条目（时间戳与事件数据对）\n            Set<Map.Entry<Long, Tuple2<Long, KafkaEventDTO>>> entrySet = timestampAndEventValueKafkaDtoMap.entrySet()\n\n            // 遍历当前 eventField 下的所有时间戳和事件数据对\n            for (Map.Entry<Long, Tuple2<Long, KafkaEventDTO>> entry : entrySet) {\n                Long currentTimestamp = entry.getKey() // 当前条目的时间戳\n                Tuple2<Long, KafkaEventDTO> value = entry.getValue() // 包含累加值和事件数据的元组\n\n                // 如果当前时间戳大于已记录的最大时间戳，则更新最大时间戳和最新的事件数据\n                if (currentTimestamp > maxTimestamp) {\n                    maxTimestamp = currentTimestamp\n                    latestEventKafkaDTO = value.f1 // 获取元组中的 EventKafkaDTO 对象\n                }\n            }\n        }\n\n        // 返回找到的最新的 EventKafkaDTO 对象\n        return latestEventKafkaDTO\n    }\n\n\n    /**\n     * 将每个事件窗口步长数据集累加的值，添加到窗口大小数据集中bigMapState中\n     */\n    private void updateBigMapWithSmallMap(long timestamp) throws Exception {\n        for (Map.Entry<String, Tuple2<Long, KafkaEventDTO>> smallMapEntry : smallMapState.entries()) {\n            String eventField = smallMapEntry.getKey()\n            Tuple2<Long, KafkaEventDTO> eventValueAndKafkaDtoTuple2 = smallMapEntry.getValue()\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueMap = bigMapState.get(eventField)\n            if (timestampAndEventValueMap == null || timestampAndEventValueMap.isEmpty()) {\n                timestampAndEventValueMap = new HashMap<>()\n            }\n            timestampAndEventValueMap.put(timestamp, eventValueAndKafkaDtoTuple2)\n            bigMapState.put(eventField, timestampAndEventValueMap)\n        }\n        // 当前窗口步长的数据已经添加到窗口中了，清空状态\n        smallMapState.clear()\n    }\n\n    /**\n     * 清理窗口大小之外的数据\n     */\n    private void cleanupWindowData(long timestamp, Map<String, RuleCondDTO> ruleConditionMapByEventField) throws Exception {\n        for (Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapEntry : bigMapState.entries()) {\n            String eventField = bigMapEntry.getKey()\n            Map<Long, Tuple2<Long, KafkaEventDTO>> timestampAndEventValueMap = bigMapEntry.getValue()\n            RuleCondDTO ruleCondDTO = ruleConditionMapByEventField.get(eventField)\n            if (Objects.isNull(ruleCondDTO)) {\n                log.warn(\"清理窗口大小之外的数据时，存在规则条件中不存在的数据\")\n                continue\n            }\n            long windowSize = TimeUtil.toMillis(ruleCondDTO.getWindowValue(), TimeUnitEnum.fromEnUnit(ruleCondDTO.getWindowUnit()))\n            long windowThresholdTime = timestamp - windowSize\n            Iterator<Map.Entry<Long, Tuple2<Long, KafkaEventDTO>>> iterator = timestampAndEventValueMap.entrySet().iterator()\n            while (iterator.hasNext()) {\n                Map.Entry<Long, Tuple2<Long, KafkaEventDTO>> next = iterator.next()\n                Long time = next.getKey()\n                if (time <= windowThresholdTime) {\n                    iterator.remove()\n                }\n            }\n            bigMapState.put(eventField, timestampAndEventValueMap)\n        }\n    }\n\n    /**\n     * 日志打印\n     */\n    private void logBigMapState(String currentKey, String ruleCode, Set<String> eventFieldList, MapState<String,\n            Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMapState) throws Exception {\n        Map<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> bigMap = new HashMap<>()\n        Iterator<Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>>> iterator = bigMapState.iterator()\n        while (iterator.hasNext()) {\n            Map.Entry<String, Map<Long, Tuple2<Long, KafkaEventDTO>>> next = iterator.next()\n            bigMap.put(next.getKey(), next.getValue())\n        }\n        log.warn(\"ProcessorOne对象onTimer方法结束 currentKey={}, ruleCode={}, eventFieldList={}, bigMapState={}\",\n                currentKey, ruleCode, JsonUtil.toJsonString(eventFieldList), JsonUtil.toJsonString(bigMap))\n    }\n\n    /**\n     * 评估事件结果，根据给定的条件操作符返回最终结果。\n     *\n     * @param eventFieldAndWarnResult 包含事件代码及其对应的警告结果的映射\n     * @param conditionOperator 条件操作符，支持 AND 和 OR\n     * @return 根据条件操作符计算后的最终结果（true 或 false）\n     */\n    boolean evaluateEventResults(Map<String, Boolean> eventFieldAndWarnResult, String conditionOperator) {\n        // 检查输入是否为 null 或为空\n        if (eventFieldAndWarnResult == null || eventFieldAndWarnResult.isEmpty()) {\n            return false\n        }\n\n        // 如果只有一个元素，直接返回该元素的值\n        if (eventFieldAndWarnResult.size() == 1) {\n            return eventFieldAndWarnResult.values().iterator().next()\n        }\n\n        // 确定操作符类型\n        RuleCondCombOpEnum opEnum = RuleCondCombOpEnum.fromCode(conditionOperator)\n\n        // 初始化结果，根据操作符类型\n        boolean result\n        if (opEnum == RuleCondCombOpEnum.AND) {\n            result = true // 对于 AND，初始值为 true\n            for (Boolean eventResult : eventFieldAndWarnResult.values()) {\n                if (!eventResult) {\n                    return false // 任何一个 false 都返回 false\n                }\n            }\n        } else if (opEnum == RuleCondCombOpEnum.OR) {\n            result = false // 对于 OR，初始值为 false\n            for (Boolean eventResult : eventFieldAndWarnResult.values()) {\n                if (eventResult) {\n                    return true // 任何一个 true 都返回 true\n                }\n            }\n        } else {\n            throw new IllegalArgumentException(\"Unsupported condition operator: \" + conditionOperator)\n        }\n\n        return result\n    }\n\n}\n',
        'system', 'system', '2024-12-29 19:07:18', '2025-01-04 18:00:41');

-- ----------------------------
-- Table structure for slr_rule_target
-- ----------------------------
DROP TABLE IF EXISTS `slr_rule_target`;
CREATE TABLE `slr_rule_target`
(
    `id`           bigint UNSIGNED                                        NOT NULL AUTO_INCREMENT COMMENT '自增主键ID',
    `channel`      varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '渠道',
    `target_code`  varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '目标编号',
    `target_field` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '目标字段',
    `target_name`  varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '目标名称',
    `target_desc`  varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '目标描述',
    `creator`      varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '创建用户',
    `updater`      varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '更新用户',
    `create_time`  datetime                                               NULL DEFAULT NULL COMMENT '创建时间',
    `update_time`  datetime                                               NULL DEFAULT NULL COMMENT '创建时间',
    PRIMARY KEY (`id`) USING BTREE,
    UNIQUE INDEX `uk_target_code` (`target_code` ASC) USING BTREE
) ENGINE = InnoDB
  AUTO_INCREMENT = 5
  CHARACTER SET = utf8mb4
  COLLATE = utf8mb4_bin COMMENT = '风控规则目标表'
  ROW_FORMAT = DYNAMIC;

